import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom"; // ✅
import "../styles/login.css"; // ✅ corregido

function Login() {
  const navigate = useNavigate(); // ✅

  const [documento, setDocumento] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [mensajeError, setMensajeError] = useState("");
  const [showPassword1, setShowPassword1] = useState(false);
  const [showPassword2, setShowPassword2] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!documento || !password || !confirmPassword) {
      setMensajeError("❌ Debes completar todos los campos.");
      return;
    }

    if (password !== confirmPassword) {
      setMensajeError("❌ Las contraseñas no coinciden.");
      return;
    }

    setMensajeError("");

    // ✅ REDIRECCIÓN CORRECTA
    navigate("/cuenta");
  };

  return (
    <div className="login-container">
      <h1 className="titulo">Inicio</h1>
      <p className="subtitulo">Bienvenido a nuestro menú de inicio.</p>

      <form className="formulario" onSubmit={handleSubmit}>
        <label htmlFor="documento">Documento</label>
        <div className="input-box">
          <span className="icon">👤</span>
          <input
            type="text"
            id="documento"
            placeholder="XXX.XXX.XXX"
            value={documento}
            onChange={(e) => setDocumento(e.target.value)}
            required
          />
        </div>

        <label htmlFor="password">Contraseña</label>
        <div className="input-box">
          <span className="icon">🔒</span>
          <input
            type={showPassword1 ? "text" : "password"}
            id="password"
            placeholder="••••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
          <span className="eye" onClick={() => setShowPassword1(!showPassword1)}>
            👁️
          </span>
        </div>

        <label htmlFor="confirmPassword">Confirmar contraseña</label>
        <div className="input-box">
          <span className="icon">🔒</span>
          <input
            type={showPassword2 ? "text" : "password"}
            id="confirmPassword"
            placeholder="••••••••••"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
            required
          />
          <span className="eye" onClick={() => setShowPassword2(!showPassword2)}>
            👁️
          </span>
        </div>

        {mensajeError && (
          <p style={{ color: "#ff4c4c", fontWeight: "bold" }}>
            {mensajeError}
          </p>
        )}

        <button type="submit" className="btn">Acceder</button>

        <p className="registro">
          ¿No tienes cuenta?{" "}
          <Link to="/registro">Regístrate aquí</Link>
        </p>

        <p className="texto-sec">
          ¿Olvidaste la contraseña?{" "}
          <Link to="/recuperar">Recuperar</Link>
        </p>

        <div className="footer">
          <p>
            © {new Date().getFullYear()} Financiero. Todos los derechos reservados.
          </p>
        </div>
      </form>
    </div>
  );
}

export default Login;
